// // This module implements a 5-bit wide 2-to-1 demultiplexer. The output will be determined by the sel signal; when sel is 0, the output will be equal to inB, and when sel is 1, the output will be set to inA.
module top_module(out, inA, inB, sel);output reg [4:0] out;

    input [4:0] inA;
    input [4:0] inB;
    input sel;

    always @(inA, inB, sel) begin
        if (sel == 0) begin
            out <= inA;
        end
        else
            out <= inB;        
    end

endmodule
